import{_ as e,o,c as r,a3 as a}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Getting Started with Notely","description":"Install Notely, open your first workspace, and understand the key concepts in under 5 minutes.","frontmatter":{"title":"Getting Started with Notely","description":"Install Notely, open your first workspace, and understand the key concepts in under 5 minutes.","keywords":"install, setup, workspace, first launch, getting started","category":"Getting Started"},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md","lastUpdated":1784054081000}'),n={name:"getting-started/index.md"};function d(i,t,s,l,c,p){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>Notely is a desktop Markdown notes app for Windows. Your notes live as plain <code>.md</code> files in a folder of your choice — no accounts required, no cloud lock-in.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Details</th></tr></thead><tbody><tr><td><strong>Platform</strong></td><td>Windows 10 / 11 (x64)</td></tr><tr><td><strong>Storage</strong></td><td>~120 MB for the application</td></tr><tr><td><strong>Network</strong></td><td>Not required for core features</td></tr><tr><td><strong>Git</strong></td><td>Optional — required only for Git features</td></tr></tbody></table><h2 id="download-install" tabindex="-1">Download &amp; Install <a class="header-anchor" href="#download-install" aria-label="Permalink to &quot;Download &amp; Install&quot;">​</a></h2><ol><li>Go to the <a href="https://github.com/WGLabz/notely/releases/latest" target="_blank" rel="noreferrer">latest release on GitHub</a>.</li><li>Download the portable <code>.exe</code> file.</li><li>Run it — no installer needed.</li></ol><div class="tip custom-block"><p class="custom-block-title">Portable App</p><p>Notely is a portable executable. You can run it from any folder, including a USB drive or a synced folder.</p></div><h2 id="open-your-workspace" tabindex="-1">Open Your Workspace <a class="header-anchor" href="#open-your-workspace" aria-label="Permalink to &quot;Open Your Workspace&quot;">​</a></h2><p>A <strong>workspace</strong> is a folder on your computer where your notes live. Notely reads <code>.md</code> files from this folder and its subfolders.</p><p><strong>First launch:</strong></p><ol><li>Open Notely.</li><li>The workspace picker appears automatically.</li><li>Click <strong>Open Workspace</strong> and select a folder.</li><li>Notely loads your notes.</li></ol><p><strong>Subsequent launches:</strong></p><p>Use <strong>File → Open Recent</strong> or the command palette (<code>Ctrl + K</code>) to reopen a recent workspace instantly.</p><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concept</th><th>What it is</th></tr></thead><tbody><tr><td><strong>Workspace</strong></td><td>A folder containing your Markdown notes</td></tr><tr><td><strong>Note</strong></td><td>A single <code>.md</code> file inside the workspace</td></tr><tr><td><strong>Folder</strong></td><td>A subfolder for organizing related notes</td></tr><tr><td><strong>.notes-app</strong></td><td>A hidden folder Notely creates for note history and support data</td></tr></tbody></table><h2 id="what-to-do-next" tabindex="-1">What to Do Next <a class="header-anchor" href="#what-to-do-next" aria-label="Permalink to &quot;What to Do Next&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:1.5rem;"><p><strong>New to Notely?</strong> → <a href="/getting-started/first-note.html">Create your first note</a></p><p><strong>Ready to write?</strong> → <a href="/editor/">Editor overview</a></p><p><strong>Coming from another tool?</strong> → <a href="/editor/markdown-guide.html">Feature Reference</a></p><p><strong>Need Git integration?</strong> → <a href="/git/">Git overview</a></p></div><h2 id="help-at-any-time" tabindex="-1">Help at Any Time <a class="header-anchor" href="#help-at-any-time" aria-label="Permalink to &quot;Help at Any Time&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Shortcut</th><th>Action</th></tr></thead><tbody><tr><td><code>F1</code></td><td>Open Help Center (in-app)</td></tr><tr><td><code>Ctrl + /</code></td><td>Open Keyboard Shortcuts</td></tr><tr><td><code>Ctrl + K</code></td><td>Open Command Palette</td></tr><tr><td><code>Ctrl + Shift + F</code></td><td>Search all notes</td></tr></tbody></table>',19)])])}const g=e(n,[["render",d]]);export{u as __pageData,g as default};
